import com.pinterest.ktlint.rule.engine.core.api.RuleProvider
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class AnnotatedTypeArgumentListFormattingTest {
    private val annotationRuleAssertThat =
        assertThatRule(
            provider = { AnnotationRule() },
            additionalRuleProviders = setOf(
                // WrappingRule must be loaded in order to run TrailingCommaOnCallSiteRule
                RuleProvider { WrappingRule() },
                RuleProvider { TrailingCommaOnCallSiteRule() },
            ),
        )

    @Test
    fun `Given multiple type-use annotations inside a type argument list then do not wrap the type argument`() {
        val code =
            """
            data class FooRequestDto(
                val data: List<@Valid @NotNull FooDto>,
            )
            """.trimIndent()

        annotationRuleAssertThat(code).hasNoLintViolations()
    }
}
